## 2. Tạo script test tool executor

Chạy đoạn này để tạo `test_agent_tools.py`.

```python
from pathlib import Path

# Tao file test_agent_tools.py
content = r'''
from agent_tools import AgentToolExecutor


def main():
    # Khoi tao executor trong workspace hien tai
    executor = AgentToolExecutor(".")

    print("Test 1: Liet ke thu muc")
    print(executor.execute({
        "tool": "list_dir",
        "path": "."
    }))

    print("\nTest 2: Tao file requirements.tft")
    print(executor.execute({
        "tool": "write_file",
        "path": "requirements.tft",
