Nếu đoạn này pass, nghĩa là quyền ghi file đã ổn. Khi đó vấn đề còn lại chỉ nằm ở việc `cli.py` chưa gọi executor.

---

## 3. Tạo file `agent_runtime_bridge.py`

File này là cầu nối để `cli.py` gọi sau mỗi response của model.

```python
from pathlib import Path

# Tao file agent_runtime_bridge.py
content = r'''
import json
from agent_tools import execute_tool_calls_from_response, get_system_tool_instructions


def enhance_system_prompt(system_prompt):
    # Gan huong dan tool vao system prompt
    if system_prompt is None:
        system_prompt = ""

    marker = "Ban co kha nang thao tac voi he thong thong qua tool call JSON"

    if marker in system_prompt:
        return system_prompt

    return system_prompt + "\n\n" + get_system_tool_instructions()


def handle_agent_response(assistant_response, workspace="."):
    # Thuc thi tool calls trong response cua assistant
    tool_execution = execute_tool_calls_from_response(
        assistant_response,
        workspace=workspace
    )

    return tool_execution


def tool_result_to_message(tool_execution):
    # Chuyen ket qua tool thanh message dua nguoc vao model
    return (
        "Ket qua thuc thi tool:\n"
        + json.dumps(tool_execution, ensure_ascii=False, indent=2)
        + "\n\nHay phan tich ket qua tren. Neu thao tac da thanh cong, hay xac nhan ngan gon. "
        + "Neu co loi, hay tiep tuc sua bang tool call JSON."
    )


def process_response_and_maybe_append(messages, assistant_response, workspace="."):
    # Ham tien ich cho cli.py neu dang dung messages list
    tool_execution = handle_agent_response(
        assistant_response,
        workspace=workspace
    )

    messages.append({
        "role": "assistant",
        "content": assistant_response
    })

    if tool_execution.get("has_tool_calls"):
        messages.append({
            "role": "user",
            "content": tool_result_to_message(tool_execution)
        })

        return {
            "has_tool_calls": True,
            "messages": messages,
            "tool_execution": tool_execution
        }

    return {
        "has_tool_calls": False,
        "messages": messages,
        "tool_execution": tool_execution
    }
'''

Path("agent_runtime_bridge.py").write_text(content, encoding="utf-8")
print("Da tao agent_runtime_bridge.py")
```

---

## 4. Cách gắn vào `cli.py`

Bạn cần sửa `cli.py` tại 3 vị trí.

### Vị trí 1: import

Thêm ở đầu file:

```python
from agent_runtime_bridge import (
    enhance_system_prompt,
    process_response_and_maybe_append,
    tool_result_to_message
)
```

---

### Vị trí 2: system prompt

Nếu trong `cli.py` có dòng kiểu:

```python
system_prompt = "..."
```

Thêm ngay sau đó:

```python
system_prompt = enhance_system_prompt(system_prompt)
```

Nếu `cli.py` tạo message trực tiếp kiểu:

```python
messages = [
    {"role": "system", "content": "..."}
]
```

thì sửa thành:

```python
messages = [
    {
        "role": "system",
        "content": enhance_system_prompt("...")
    }
]
```

Nếu `messages` đã tồn tại rồi, có thể thêm đoạn sau sau khi tạo `messages`:

```python
for message in messages:
    # Tim system message va gan tool instruction
    if message.get("role") == "system":
        message["content"] = enhance_system_prompt(message.get("content", ""))
        break
else:
    # Neu chua co system message thi them moi
    messages.insert(0, {
        "role": "system",
        "content": enhance_system_prompt("")
    })
```

---

### Vị trí 3: sau khi nhận response từ model

Trong `cli.py`, tìm đoạn kiểu:

```python
assistant_response = completion.choices[0].message.content
print(assistant_response)
messages.append({
    "role": "assistant",
    "content": assistant_response
})
```

Sửa thành:

```python
assistant_response = completion.choices[0].message.content
print(assistant_response)

tool_state = process_response_and_maybe_append(
    messages,
    assistant_response,
    workspace="."
)

if tool_state["has_tool_calls"]:
    print("\n=== TOOL EXECUTION RESULT ===")
    print(tool_state["tool_execution"])

    # Goi model them mot lan de no phan tich ket qua tool
    followup = client.chat.completions.create(
        model=model,
        messages=messages
    )

    final_response = followup.choices[0].message.content

    print("\n=== AGENT FINAL RESPONSE ===")
    print(final_response)

    messages.append({
        "role": "assistant",
        "content": final_response
    })
```

Nếu `cli.py` không dùng OpenAI SDK mà gọi `server.py` bằng HTTP, thì ý tưởng tương tự:

```python
assistant_response = response_text
print(assistant_response)

tool_state = process_response_and_maybe_append(
    messages,
    assistant_response,
    workspace="."
)

if tool_state["has_tool_calls"]:
    # Gui messages da co ket qua tool len server them mot lan nua
    # Tuy theo cli.py hien tai, thay ham call_server bang ham dang co
    final_response = call_server(messages)

    print("\n=== AGENT FINAL RESPONSE ===")
    print(final_response)

    messages.append({
        "role": "assistant",
        "content": final_response
    })
```

---

## 5. Tạo script kiểm tra `cli.py` đã tích hợp đúng chưa

```python
from pathlib import Path

# Tao file check_cli_integration.py
content = r'''
from pathlib import Path


def main():
    # Kiem tra cli.py co tich hop tool bridge chua
    cli_path = Path("cli.py")

    if not cli_path.exists():
        print("Khong tim thay cli.py")
        return

    text = cli_path.read_text(encoding="utf-8", errors="ignore")

    checks = {
        "import_agent_runtime_bridge": "agent_runtime_bridge" in text,
        "enhance_system_prompt": "enhance_system_prompt" in text,
        "process_response_and_maybe_append": "process_response_and_maybe_append" in text,
        "tool_execution_print": "TOOL EXECUTION RESULT" in text or "tool_execution" in text,
    }

    print("KET QUA KIEM TRA CLI.PY:")
    for name, ok in checks.items():
        print(f"{name}: {'OK' if ok else 'MISSING'}")

    if all(checks.values()):
        print("\ncli.py co ve da duoc tich hop tool executor.")
    else:
        print("\ncli.py chua duoc tich hop day du.")


if __name__ == "__main__":
    main()
'''

Path("check_cli_integration.py").write_text(content, encoding="utf-8")
print("Da tao check_cli_integration.py")
```

